package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.File;
import java.io.FileOutputStream;
import java.io.IOException;
import java.io.OutputStreamWriter;
import java.nio.charset.Charset;

import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

public class CSVFormatTest {

    @Test
    public void testPrint() throws IOException {
        // Given
        File file = new File("test.csv");
        Charset charset = Charset.defaultCharset();
        CSVFormat csvFormat = CSVFormat.DEFAULT;
        CSVPrinter csvPrinterMock = mock(CSVPrinter.class);

        // Mock the OutputStreamWriter and FileOutputStream
        OutputStreamWriter outputStreamWriterMock = mock(OutputStreamWriter.class);
        Mockito.doReturn(outputStreamWriterMock).when(Mockito.spy(OutputStreamWriter.class)).<init>(any(FileOutputStream.class), any(Charset.class));

        // Mock the CSVPrinter
        Mockito.doReturn(csvPrinterMock).when(Mockito.spy(CSVPrinter.class)).<init>(outputStreamWriterMock, csvFormat);

        // When
        CSVPrinter csvPrinter = csvFormat.print(file, charset);

        // Then
        assertNotNull(csvPrinter);
        assertEquals(csvPrinterMock, csvPrinter);
    }
}
